#include "jit.h"
#include <inttypes.h>
#include <stdio.h>
#include <string.h>
#include <time.h>
#define ITERATIONS 2000000u
static uint64_t now_ns(void){struct timespec t;timespec_get(&t,TIME_UTC);return(uint64_t)t.tv_sec*1000000000ull+(uint64_t)t.tv_nsec;}
static int make_add(TurboJSIRFunction*f){TurboJSIRInstruction in;uint16_t a,k,r;TurboJS_IRFunctionInit(f,1);a=TurboJS_IRAllocateRegister(f);k=TurboJS_IRAllocateRegister(f);r=TurboJS_IRAllocateRegister(f);memset(&in,0,sizeof(in));in.opcode=TURBOJS_IR_ARGUMENT;in.destination=a;if(TurboJS_IREmit(f,in)!=TURBOJS_IR_OK)return 0;in.opcode=TURBOJS_IR_CONSTANT_I64;in.destination=k;in.immediate=1;if(TurboJS_IREmit(f,in)!=TURBOJS_IR_OK)return 0;in.opcode=TURBOJS_IR_ADD_I64;in.destination=r;in.left=a;in.right=k;if(TurboJS_IREmit(f,in)!=TURBOJS_IR_OK)return 0;in.opcode=TURBOJS_IR_RETURN_I64;in.left=r;return TurboJS_IREmit(f,in)==TURBOJS_IR_OK;}
int main(void){TurboJSIRFunction f;TurboJSIRDiagnostic d;TurboJSNativeFunction*n=NULL;TurboJSFeedbackVector fb;TurboJSOptimizedFunction*o=NULL;TurboJSOptimizingStats st;uint64_t a,b;int64_t arg=41,out=0;unsigned i;if(!make_add(&f))return 1;if(TurboJS_BaselineCompile(&f,&n,&d)!=TURBOJS_IR_OK)return 2;TurboJS_FeedbackVectorInit(&fb,1);for(i=0;i<1200;i++){TurboJS_FeedbackObserveCall(&fb,&arg,1);TurboJS_FeedbackObserveResult(&fb,42);}if(TurboJS_OptimizingCompile(&f,&fb,&o,&st,&d)!=TURBOJS_IR_OK)return 3;a=now_ns();for(i=0;i<ITERATIONS;i++)if(TurboJS_IRExecute(&f,&arg,1,&out)!=TURBOJS_IR_OK)return 4;b=now_ns();printf("interpreter_ns_per_call=%.3f\n",(double)(b-a)/ITERATIONS);a=now_ns();for(i=0;i<ITERATIONS;i++)if(TurboJS_NativeInvoke(n,&arg,1,&out)!=TURBOJS_IR_OK)return 5;b=now_ns();printf("baseline_ns_per_call=%.3f\n",(double)(b-a)/ITERATIONS);a=now_ns();for(i=0;i<ITERATIONS;i++)if(TurboJS_OptimizedInvoke(o,&arg,1,&out)!=TURBOJS_IR_OK)return 6;b=now_ns();printf("optimized_ns_per_call=%.3f\n",(double)(b-a)/ITERATIONS);printf("native_bytes=%zu optimized_bytes=%zu result=%" PRId64 "\n",TurboJS_NativeCodeSize(n),TurboJS_OptimizedCodeSize(o),out);TurboJS_OptimizedFunctionDestroy(o);TurboJS_NativeFunctionDestroy(n);TurboJS_IRFunctionDestroy(&f);return out==42?0:7;}
